import bisect
import random


class MajorityChecker:
    def __init__(self, arr):
        self.arr = arr
        self.pos = {}
        for i, v in enumerate(arr):
            self.pos.setdefault(v, []).append(i)
        self.rng = random.Random(12345)
    def _count(self, v, left, right):
        idx = self.pos[v]
        return bisect.bisect_right(idx, right) - bisect.bisect_left(idx, left)
    def query(self, left, right, threshold):
        for _ in range(20):
            v = self.arr[self.rng.randint(left, right)]
            if self._count(v, left, right) >= threshold:
                return v
        return -1

