var MajorityChecker = function(arr) {
    this.arr = arr;
    this.pos = new Map();
    for (let i = 0; i < arr.length; i++) {
        if (!this.pos.has(arr[i])) this.pos.set(arr[i], []);
        this.pos.get(arr[i]).push(i);
    }
    let s = 12345;
    this.rand = function() { s = (s * 1103515245 + 12345) & 0x7fffffff; return s; };
};
MajorityChecker.prototype._count = function(v, left, right) {
    const idx = this.pos.get(v);
    const lower = (target) => { let lo = 0, hi = idx.length; while (lo < hi) { const m = (lo + hi) >> 1; if (idx[m] < target) lo = m + 1; else hi = m; } return lo; };
    const upper = (target) => { let lo = 0, hi = idx.length; while (lo < hi) { const m = (lo + hi) >> 1; if (idx[m] <= target) lo = m + 1; else hi = m; } return lo; };
    return upper(right) - lower(left);
};
MajorityChecker.prototype.query = function(left, right, threshold) {
    for (let t = 0; t < 20; t++) {
        const i = left + (this.rand() % (right - left + 1));
        const v = this.arr[i];
        if (this._count(v, left, right) >= threshold) return v;
    }
    return -1;
};
